// Filter PJM queue to Virginia target counties and active large projects
const response = $input.first().json;

const VA_COUNTIES = [
  'loudoun', 'fauquier', 'stafford',
  'prince william', 'clarke', 'warren'
];

// PJM Data Miner 2 returns { items: [...] } or raw array
const rows = Array.isArray(response)
  ? response
  : response?.items || response?.data || [];

console.log(`Total PJM rows received: ${rows.length}`);

const filtered = rows.filter(row => {
  const countyRaw = String(row.COUNTY || row.county || '').toLowerCase().trim();
  const stateRaw = String(row.STATE || row.state || '').toUpperCase().trim();
  const status = String(row.STATUS || row.queue_status || '').toLowerCase();
  const mw = parseFloat(row.CAPACITY_MW || row.capacity_mw || row.MW || row.mw || 0);

  const isVA = stateRaw === 'VA' || stateRaw === 'VIRGINIA';
  const isTargetCounty = VA_COUNTIES.some(vc => countyRaw.includes(vc));
  const isActive = status.includes('active') || status.includes('new service');
  const isLarge = mw > 50;

  return isVA && isTargetCounty && isActive && isLarge;
});

console.log(`Filtered to ${filtered.length} VA target-county active >50MW projects`);

return filtered.map(row => ({
  json: {
    source: 'pjm_queue',
    url: `https://dataminer2.pjm.com/feed/ivmsc_queue/export`,
    raw_text: [
      row.PROJECT_NAME || row.project_name || row.NAME || '',
      `County: ${row.COUNTY || row.county || ''}`,
      `State: VA`,
      `MW: ${row.CAPACITY_MW || row.capacity_mw || row.MW || ''}`,
      `Status: ${row.STATUS || row.queue_status || ''}`,
      `Queue Date: ${row.QUEUE_DATE || row.queue_date || row.SUBMITTED_DATE || ''}`,
      `Owner: ${row.OWNER || row.customer_name || ''}`,
      `Type: ${row.FUEL_TYPE || row.resource_type || ''}`,
    ].filter(s => s && !s.endsWith(': ')).join(' | '),
    captured_at: new Date().toISOString(),
    processed: false,
  }
}));
